<template>
  <div>
    <my-header 
      :user="user"
      :orders="orders"
    />
    <div class="pay_title">
      <div class="pay_content_title">
        <h4 
          v-for="(item,index) of title"
          :key="index"
          class="item_title"
        >
          {{ item }}
        </h4>
      </div>
      <div class="pay_content">
        <div 
          class="pay_item"
          v-for="(item,index) of listData"
          :key="index"
        >
          <div class="show_img_title">
            <div class="img">
              <img :src="item.foot_img">
            </div>
            <span
              class="item_name"
              :data-id="item.shopid"
              :data-pid="item.shoppid"
              @click.stop="toDetail($event)"
            >{{ item.foot_name }}</span>
            <span class="item_title">{{ item.foot_notice }}</span>
          </div>
          <div class="price">
            ￥{{ item.price }}
          </div>
          <div class="num">
            <span 
              class="reduce"
              @click="reduce(item)"
            >-</span>
            <input 
              type="text"
              class="txt"
              v-model.number="item.num"
            >
            <span 
              class="add"
              @click="add(item)"
            >+</span>
          </div>
          <div class="cheap">
            -￥{{ item.reduce_price }}
          </div>
          <div class="price_total">
            ￥{{ (item.price - item.reduce_price) * item.num | tofix }}
          </div>
          <div class="delete">
            <span 
              class="delete_txt"
              @click="deleteOrder(item)"
            >删除</span>
          </div>
        </div>
      </div>
      <div class="has_pay">
        <div class="pay">
          应付金额:
          <span class="mark">￥</span>
          <span class="pay_moneny">{{ monenyTotal| tofix }}</span>
        </div>
        <div class="confirm">
          确认
        </div>
      </div>
    </div>
    <my-footer />
  </div>
</template>
<script>
import Api from "../api/pay/api.js";
import myFooter from "../commen/components/footer.vue";
import myHeader from "./header.vue";
export default {
    data (){
        return {
            title:[
                "商品",
                "单价",
                "数量",
                "优惠",
                "小计",
                " "
            ],
            // 购物商品列表
            listData:[],
            // 用户预购买数
            orders:0,
            // 用户登陆信息
            user:{}
        };
    },
    created (){
        this.getUserOrder();
        this.getUser();
        this.getUserOrders();

    },
    filters:{
        tofix (value){
            return value.toFixed(2);

        }

    },
    components:{
        myFooter,
        myHeader
    },
    methods:{
        // 获取用户信息
        getUser (){
            this.axios.get(`${Api.user}`).then(response => {
                if(response.code === 200){
                    this.user = response.data;
                }
                return;
            }).catch(error => {
                console.log(error);
            });

        },
        // 获取用户订单数
        getUserOrders (){
            this.axios.get(Api.orderNum).then(response => {
                if(response.code === 200){

                    this.orders = response.data.order_num;
                }
                return;
            }).catch(error => {
                console.log(error);
            });
        },
        // 获取用户订单
        getUserOrder (){
            this.axios.get(`${Api.orderList}`).then(response => {
                if(response.code === 200){
                    
                    this.listData = response.data;
                }
                return;
            }).catch(error => {
                console.log(error);
            });

        },
        // 减少商品购买
        reduce (item){
            item.num --;
            if(item.num < 1){
                item.num = 1;
            }

        },
        // 增加商品购买
        add (item){
            item.num ++;

        },
        // 删除用户订单
        deleteOrder (item){
            let index = this.listData.indexOf(item);
            this.listData.splice(index,1);
            this.axios.post(`${Api.orders}`,{
                id:item.id
            }).then(response => {
                return response;
            }).catch(error => {
                console.log(error);
            });


        },
        // 查看商品详情信息
        toDetail (event){
            const currentElementId = event.target.dataset.id,
                currentElementPid =  event.target.dataset.pid;
            this.$router.push({
                path:`/productionDetail/${currentElementPid}/${currentElementId}`
            });


        }
        


    },
    computed:{
        // 总价
        monenyTotal (){
            let monenyTotal = 0;
            this.listData.forEach(item => {
                monenyTotal += (item.price - item.reduce_price) * item.num;
            });
            return  monenyTotal;

        }
    }
    
};
</script>
<style lang="scss" scoped>
.pay_title{
    width:1000px;
    margin:0 auto;
    margin-top:20px;
    .pay_content_title{
        background-color:whitesmoke;
        overflow:hidden;
        display:flex;
        .item_title{
            $height:40px;
            height:$height;
            line-height:$height;
            text-align:center;
            color:rgb(49,49,49);
            flex:1;
            border-left:1px solid rgb(201,201,201);
            &:first-child{
                border:none;
                flex: 0 0 330px;
            }

        }

    }
    .pay_content{
        .pay_item{
            height:130px;
            border-bottom:1px solid rgb(201,201,201);
            overflow:hidden;
            display:flex;
            .show_img_title{
                height:100%;
                flex:0 0 330px;
                box-sizing: border-box;
                padding-top:20px;
                position:relative;
                .img{
                    width:150px;
                    height:90px;
                    display:inline-block;
                    img{
                        width:100%;
                        height:100%;
                    }
                }
                .item_title,.item_name{
                    position:absolute;
                    margin-left:14px;

                }
                .item_name{
                    top:30px;
                    &:hover{
                        color:blue;
                        text-decoration:underline;
                        cursor: pointer;
                    }
                }
                .item_title{
                    font-size:14px;
                    color:rgb(112,112,112);
                    top:75px;
                    
                }

            }
            .price,.num,.cheap,.price_total,.delete{
                height:100%;
                flex:1;
                text-align:center;
                line-height:130px;
                font-size:14px;
                 color:rgb(112,112,112);
                
            }
            .delete{
                .delete_txt{
                    cursor: pointer;
                    padding:5px;
                &:hover{
                    color:blue;
                }
                }

            }
            .num{
                position:relative;
                .reduce,.txt,.add{
                    $height:25px;
                    position:absolute;
                    top:53px;
                    height:$height;
                    line-height:$height;
                    border:none;
                }
                .reduce,.add{
                    width:30px;
                    border:1px solid rgb(181,181,181);
                    cursor: pointer;
                    &:hover{
                        border:1px solid #e4007f;
                    }
                }
                .reduce{
                    left:10px;
                    
                }
                .txt{
                    width:42px;
                    left:42px;
                    outline:none;
                    border-top:1px solid rgb(181,181,181);
                    border-bottom:1px solid rgb(181,181,181);
                    text-align:center;
                    font-size:17px;
                    
                }
                .add{
                    left:84px;
                }

            }
            .price_total{
                color:#e4007f;
            }
        }

    }
    .has_pay{
        margin-top:20px;
        position:relative;
        height:100px;
        .pay,.confirm{
            left:770px;
            font-size:18px;
            position:absolute;
            
        }
        .confirm{
            top:60px;
            padding:5px 50px;
            background-color:rgb(243,152,0);
            cursor: pointer;
        }
        .pay{
            .pay_moneny{
                font-size:30px;
                color:#e4007f;
                margin-left:-5px;
            }
             .mark{
                font-size:18px;
                color:#e4007f;
            }
        }

    }

}

</style>


